if (! function_exists('arxiv_search')) {
    function arxiv_search($query, $max_results = null, $start = null, $timeout = null)
    {
            $query = $query ?? '';
            $max_results = $max_results ?? 10;
            $start = $start ?? 0;
            $timeout = $timeout ?? 20;

            $timeout = max(5, min(30, (int)$timeout));
            $max_results = max(1, min(100, (int)$max_results));
            $start = max(0, min(10000, (int)$start));

            if (empty(trim($query))) {
                return ['success' => false, 'error' => 'Search query is required.'];
            }

            // Determine search prefix
            $search_query = $query;
            $has_prefix = (bool)preg_match('/^(all|ti|au|abs|co|cat|rn|id):/i', trim($query));

            // Build API URL
            $api_url = 'http://export.arxiv.org/api/query?search_query=' . urlencode($search_query)
                . '&start=' . $start
                . '&max_results=' . $max_results
                . '&sortBy=relevance&sortOrder=descending';

            // Fetch the Atom XML
            $ctx = stream_context_create([
                'http' => ['method' => 'GET', 'timeout' => $timeout, 'header' => "User-Agent: arxiv_search/1.0 (self-bootstrapping-agent)\r\n", 'ignore_errors' => true],
                'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
            ]);
            $body = @file_get_contents($api_url, false, $ctx);
            if ($body === false) {
                return ['success' => false, 'error' => 'Failed to fetch arXiv API: ' . (error_get_last()['message'] ?? 'unknown')];
            }

            // Check HTTP status
            $status = 200;
            if (isset($http_response_header)) {
                foreach ($http_response_header as $h) {
                    if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                }
            }
            if ($status >= 400) {
                return ['success' => false, 'error' => "arXiv API returned HTTP $status"];
            }

            // Parse Atom XML
            libxml_use_internal_errors(true);
            $xml = @simplexml_load_string($body);
            if ($xml === false) {
                $errors = libxml_get_errors();
                libxml_clear_errors();
                return ['success' => false, 'error' => 'Failed to parse arXiv XML response: ' . ($errors[0]->message ?? 'unknown')];
            }

            // Register Atom namespace
            $atom_ns = 'http://www.w3.org/2005/Atom';
            $arxiv_ns = 'http://arxiv.org/schemas/atom';
            $opensearch_ns = 'http://a9.com/-/spec/opensearch/1.1/';

            // Get total results from OpenSearch
            $total_results = 0;
            $osr = $xml->children($opensearch_ns);
            if (isset($osr->totalResults)) {
                $total_results = (int)$osr->totalResults;
            }

            // Parse entries
            $papers = [];
            foreach ($xml->entry as $entry) {
                // arXiv ID (from the link with rel="alternate" or from the id element)
                $arxiv_id = '';
                $id_full = (string)$entry->id; // e.g. http://arxiv.org/abs/1234.56789v1
                $arxiv_id = preg_replace('/^http[s]?:\/\/arxiv\.org\/abs\//', '', $id_full);
                $arxiv_id = preg_replace('/v\d+$/', '', $arxiv_id); // Remove version suffix

                // Title
                $title = (string)$entry->title;
                $title = str_replace("\n", ' ', $title);
                $title = preg_replace('/\s+/', ' ', $title);
                $title = trim($title);

                // Abstract / summary
                $abstract = (string)$entry->summary;
                $abstract = str_replace("\n", ' ', $abstract);
                $abstract = preg_replace('/\s+/', ' ', $abstract);
                $abstract = trim($abstract);

                // Published and updated dates
                $published = (string)$entry->published;
                $updated = (string)$entry->updated;

                // Authors
                $authors = [];
                foreach ($entry->author as $author) {
                    $authors[] = (string)$author->name;
                }

                // Links (PDF, abstract, DOI)
                $links = [];
                $doi = '';
                $pdf_url = '';
                $abstract_url = '';
                foreach ($entry->link as $link) {
                    $rel = (string)$link['rel'];
                    $href = (string)$link['href'];
                    $title_attr = (string)$link['title'];

                    if ($rel === 'alternate') {
                        $abstract_url = $href;
                    } elseif ($rel === 'related' && $title_attr === 'pdf') {
                        // Try PDF links
                        foreach ($entry->link as $l2) {
                            if ((string)$l2['title'] === 'pdf') {
                                $pdf_url = (string)$l2['href'];
                            }
                        }
                        $pdf_url = $href;
                    } elseif ($rel === 'http://arxiv.org/schemas/atom/doi') {
                        $doi = $href;
                    }
                }

                // Better link extraction
                $pdf_url = '';
                $abstract_url = '';
                foreach ($entry->link as $link) {
                    $rel = (string)$link['rel'];
                    $href = (string)$link['href'];
                    $type = (string)$link['type'];
                    if ($rel === 'alternate') {
                        $abstract_url = $href;
                    } elseif ($type === 'application/pdf') {
                        $pdf_url = $href;
                    } elseif ($rel === 'related' && $type === 'application/pdf') {
                        $pdf_url = $href;
                    }
                }

                // DOI from the id if available
                $doi_match = '';
                foreach ($entry->link as $link) {
                    $rel = (string)$link['rel'];
                    if ($rel === 'http://arxiv.org/schemas/atom/doi') {
                        $doi_match = (string)$link['href'];
                    }
                }

                // ARXIV primary category
                $primary_cat = '';
                foreach ($entry->category as $cat) {
                    $term = (string)$cat['term'];
                    $primary = (string)$cat['primary'];
                    if ($primary === 'true' || $primary === '1') {
                        $primary_cat = $term;
                    }
                }
                // If no primary attribute, first category is primary
                if (empty($primary_cat)) {
                    $cats = $entry->category;
                    if (count($cats) > 0) {
                        $primary_cat = (string)$cats[0]['term'];
                    }
                }

                // All categories
                $categories = [];
                foreach ($entry->category as $cat) {
                    $categories[] = (string)$cat['term'];
                }

                // Comment (e.g. journal reference)
                $comment = (string)$entry->children($arxiv_ns)->comment;
                $journal_ref = (string)$entry->children($arxiv_ns)->journal_ref;

                $papers[] = [
                    'id' => $arxiv_id,
                    'title' => $title,
                    'authors' => $authors,
                    'author_count' => count($authors),
                    'abstract' => mb_substr($abstract, 0, 2000),
                    'abstract_length' => strlen($abstract),
                    'primary_category' => $primary_cat,
                    'categories' => $categories,
                    'published' => $published,
                    'updated' => $updated,
                    'links' => [
                        'abstract' => $abstract_url ?: "https://arxiv.org/abs/{$arxiv_id}",
                        'pdf' => $pdf_url ?: "https://arxiv.org/pdf/{$arxiv_id}",
                    ],
                    'doi' => $doi_match ?: '',
                    'journal_reference' => (string)$journal_ref ?: '',
                    'comment' => (string)$comment ?: '',
                ];
            }

            $retrieved = count($papers);

            return [
                'success' => true,
                'query' => $query,
                'source' => 'arXiv.org API',
                'total_results' => $total_results,
                'results_returned' => $retrieved,
